#ifndef SRC_LIB_WIFI_UPDATE_PORTAL_PAGE_GENERATED_H
#define SRC_LIB_WIFI_UPDATE_PORTAL_PAGE_GENERATED_H

static const char kWifiUpdatePortalHtmlTemplate[] = "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>Firmware Update</title>\n  <link rel=\"stylesheet\" href=\"/update.css?v={{VERSION}}-assets1\">\n</head>\n<body>\n  <main class=\"shell\">\n    <div class=\"topbar\">\n      <div>\n        <h1 data-i18n=\"{{HEADLINE_KEY}}\">{{HEADLINE}}</h1>\n        <p class=\"sub\" data-i18n=\"{{INTRO_KEY}}\">{{INTRO}}</p>\n        <div class=\"language\">\n          <span class=\"lang-label\" data-i18n=\"language\">Language</span>\n          <div id=\"language-select\" class=\"lang-radio\">\n            <label><input type=\"radio\" name=\"lang\" value=\"en\">English</label>\n            <label><input type=\"radio\" name=\"lang\" value=\"zh\">\u4e2d\u6587</label>\n          </div>\n        </div>\n      </div>\n      <div class=\"status\">\n        <div><span data-i18n=\"configAp\">Config AP</span><strong class=\"mono\">{{AP_IP}}</strong></div>\n        <div><span data-i18n=\"stationIp\">Station IP</span><strong class=\"mono\">{{STA_IP}}</strong></div>\n      </div>\n    </div>\n\n    <nav class=\"nav\">\n      <a href=\"/\" data-i18n=\"wifiConfig\">WiFi Config</a>\n      <a href=\"/nrl\" data-i18n=\"nrlConfig\">NRL Config</a>\n      <a href=\"/audio\" data-i18n=\"audioSettings\">Audio Settings</a>\n      <a href=\"/media\" data-i18n=\"mediaConfig\">Media / Nanny</a>\n      <a href=\"/aprs\" data-i18n=\"aprsConfig\">APRS</a>\n      <a href=\"/signaling\" data-i18n=\"signalingConfig\">Signaling / CTCSS</a>\n      <a class=\"active\" href=\"/update\" data-i18n=\"firmwareUpdate\">Firmware Update</a>\n    </nav>\n\n    <p class=\"notice\"><span data-i18n=\"firmwareVersion\">Firmware version</span> {{VERSION}}</p>\n    <p class=\"notice\" data-i18n=\"otaNotice\">Select a firmware.bin file from support or from a trusted release. The device will reboot after a successful update.</p>\n\n    <section class=\"panel release-notes\">\n      <h2 data-i18n=\"releaseTitle\">0.8.22 feature updates</h2>\n      <ul>\n        <li data-i18n=\"releaseSmbPlayback\">Improved SMB/NAS music streaming stability, including FLAC playback.</li>\n        <li data-i18n=\"releaseBeaconFeedback\">\"Beacon now\" button shows \"Sent\" feedback instead of \"Saved\".</li>\n        <li data-i18n=\"releaseOtaCheck\">\"Check releases\" now saves OTA server config before querying for updates.</li>\n      </ul>\n    </section>\n\n    <section class=\"panel\">\n      <h2 data-i18n=\"remoteOtaTitle\">Remote OTA</h2>\n      <p class=\"notice\" data-i18n=\"remoteOtaIntro\">The device periodically reports its board, firmware, NRL callsign and SSID to the OTA server. HTTP is intended only for a trusted LAN; HTTPS is recommended otherwise.</p>\n      <form id=\"remote-ota-config\">\n        <label><span data-i18n=\"otaServerUrl\">OTA server URL (HTTP/HTTPS)</span><input id=\"ota-server-url\" name=\"server_url\" type=\"url\" placeholder=\"http://192.168.1.10:8080\" maxlength=\"191\"></label>\n        <label><span data-i18n=\"deviceAccessToken\">Device access token (optional)</span><input id=\"ota-device-token\" name=\"device_token\" type=\"password\" maxlength=\"95\" autocomplete=\"new-password\"></label>\n        <div class=\"actions\"><button type=\"submit\" data-i18n=\"saveOtaServer\">Save OTA server</button><button id=\"ota-check\" type=\"button\" data-i18n=\"checkReleases\">Check releases</button></div>\n      </form>\n      <p id=\"remote-ota-status\" class=\"prog-status\" data-i18n=\"remoteNotConfigured\">Not configured</p>\n      <div id=\"remote-ota-progress\" class=\"prog-wrap\" hidden>\n        <div class=\"prog-bar\"><div id=\"remote-ota-bar\"></div></div>\n      </div>\n      <label><span data-i18n=\"availableVersions\">Available versions</span><select id=\"ota-release-list\"><option value=\"\" data-i18n=\"checkReleasesFirst\">Check releases first</option></select></label>\n      <div class=\"actions\"><button id=\"ota-install\" type=\"button\" data-i18n=\"installSelectedVersion\">Install selected version</button></div>\n    </section>\n\n    <section class=\"panel\">\n      <h2 data-i18n=\"otaTitle\">WiFi Firmware Update</h2>\n      <form id=\"ota-form\" enctype=\"multipart/form-data\">\n        <input id=\"ota-file\" type=\"file\" name=\"firmware\" accept=\".bin,application/octet-stream\" required>\n        <div class=\"actions\"><button id=\"ota-submit\" type=\"submit\" data-i18n=\"uploadFirmware\">Upload firmware</button></div>\n        <div id=\"ota-progress\" class=\"prog-wrap\" hidden>\n          <div class=\"prog-bar\"><div id=\"ota-bar\"></div></div>\n          <p id=\"ota-status\" class=\"prog-status\"></p>\n        </div>\n      </form>\n    </section>\n  </main>\n  <script src=\"/update.js?v={{VERSION}}-assets1\"></script>\n</body>\n</html>\n";

#endif
